/**
 * Hermes Opportunity Review UI v1.
 *
 * Review-only UI for rows generated by Hermes Opportunity flows.
 * No AI calls, no marketplace calls, no price/inventory/listing changes.
 */
(function () {
  let user = null;
  let cache = [];
  let selectedId = null;
  const evidenceCache = new Map();

  const STATUSES = ['new', 'reviewing', 'approved', 'rejected', 'archived'];
  const TYPES = [
    'inventory_restock_review',
    'dead_stock_review',
    'listing_quality_review',
    'price_or_margin_review',
    'cost_data_completion',
    'competition_watch',
    'urgent_price_attack_review',
  ];
  const ACTIONS = ['reviewing', 'approved', 'rejected', 'archived'];

  function esc(value) {
    if (value == null) return '';
    return String(value).replace(/[&<>"']/g, c => ({
      '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;',
    }[c]));
  }

  function fmtDate(value) {
    return value ? new Date(value).toLocaleString('ko-KR') : '-';
  }

  function badge(status) {
    const colors = {
      new: ['#1a3a4a', '#64b5f6'],
      reviewing: ['#5d3a00', '#ffb74d'],
      approved: ['#1b5e20', '#69f0ae'],
      rejected: ['#4a1a1a', '#ef9a9a'],
      archived: ['#37474f', '#bdbdbd'],
    };
    const [bg, fg] = colors[status] || ['#37474f', '#bdbdbd'];
    return `<span style="background:${bg};color:${fg};padding:2px 8px;border-radius:4px;font-size:10px;font-weight:700;">${esc(status || '?')}</span>`;
  }

  function chips(values) {
    const list = Array.isArray(values) ? values : [];
    if (list.length === 0) return '<span style="color:#666;">-</span>';
    return list.map(v => `<span style="display:inline-block;background:#263238;color:#bbdefb;padding:2px 6px;border-radius:4px;font-size:10px;margin:1px 3px 1px 0;font-family:monospace;">${esc(v)}</span>`).join('');
  }

  function prettyJson(value) {
    return esc(JSON.stringify(value || {}, null, 2));
  }

  function scoreRows(evidence) {
    const scores = evidence?.score_breakdown?.scores || {};
    const names = Object.keys(scores);
    if (names.length === 0) return '<div style="color:#666;font-size:11px;">score breakdown 없음</div>';
    return `
      <div style="overflow:auto;max-height:260px;">
        <table style="width:100%;border-collapse:collapse;font-size:11px;color:#cfd8dc;">
          <thead><tr style="color:#90a4ae;text-align:left;"><th style="padding:4px;border-bottom:1px solid #263238;">score</th><th style="padding:4px;border-bottom:1px solid #263238;">points</th><th style="padding:4px;border-bottom:1px solid #263238;">status</th><th style="padding:4px;border-bottom:1px solid #263238;">reason</th></tr></thead>
          <tbody>${names.map(name => {
            const s = scores[name] || {};
            const points = s.points == null ? '-' : `${s.points}/${s.max}`;
            return `<tr><td style="padding:4px;border-bottom:1px solid #1f2933;font-family:monospace;color:#bbdefb;">${esc(name)}</td><td style="padding:4px;border-bottom:1px solid #1f2933;">${esc(points)}</td><td style="padding:4px;border-bottom:1px solid #1f2933;">${esc(s.status || '-')}</td><td style="padding:4px;border-bottom:1px solid #1f2933;">${esc(s.reason || '')}</td></tr>`;
          }).join('')}</tbody>
        </table>
      </div>
    `;
  }

  function renderListingEvidence(evidence) {
    const signal = evidence?.listing_quality_signal || null;
    const reasons = Array.isArray(evidence?.reasons) ? evidence.reasons : [];
    return `
      <div style="margin-top:10px;background:#101b22;border:1px solid #24505f;border-radius:8px;padding:10px;">
        <div style="display:flex;justify-content:space-between;gap:8px;align-items:center;margin-bottom:8px;">
          <div style="color:#80deea;font-size:12px;font-weight:700;">Listing Quality Evidence</div>
          <span style="color:#90a4ae;font-size:10px;font-family:monospace;">source: ${esc(evidence?.source || 'signal_engine')}</span>
        </div>
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:8px;">
          <div style="background:#0f0f23;border-radius:6px;padding:8px;"><div style="color:#90a4ae;font-size:10px;margin-bottom:4px;">normalized score</div><div style="color:#fff;font-weight:700;">${esc(evidence?.score_breakdown?.normalized ?? 'needs_data')}</div></div>
          <div style="background:#0f0f23;border-radius:6px;padding:8px;"><div style="color:#90a4ae;font-size:10px;margin-bottom:4px;">signal</div><div style="color:${signal ? '#ffcc80' : '#78909c'};font-weight:700;">${esc(signal?.type || 'none')}</div></div>
        </div>
        <div style="background:#0f0f23;border-radius:6px;padding:8px;margin-bottom:8px;">
          <div style="color:#90a4ae;font-size:10px;margin-bottom:4px;font-weight:700;">listing_quality_signal</div>
          <pre style="white-space:pre-wrap;word-break:break-word;color:#cfd8dc;font-size:11px;line-height:1.35;margin:0;max-height:180px;overflow:auto;">${prettyJson(signal)}</pre>
        </div>
        <div style="background:#0f0f23;border-radius:6px;padding:8px;margin-bottom:8px;">
          <div style="color:#90a4ae;font-size:10px;margin-bottom:4px;font-weight:700;">score breakdown</div>
          ${scoreRows(evidence)}
        </div>
        <div style="background:#0f0f23;border-radius:6px;padding:8px;margin-bottom:8px;">
          <div style="color:#90a4ae;font-size:10px;margin-bottom:4px;font-weight:700;">reasons</div>
          ${chips(reasons)}
        </div>
        <div style="background:#0f0f23;border-radius:6px;padding:8px;margin-bottom:8px;">
          <div style="color:#90a4ae;font-size:10px;margin-bottom:4px;font-weight:700;">recommendation</div>
          <div style="color:#e0f2f1;font-size:12px;line-height:1.45;">${esc(evidence?.recommendation || '-')}</div>
        </div>
        <div style="background:#0f0f23;border-radius:6px;padding:8px;">
          <div style="color:#90a4ae;font-size:10px;margin-bottom:4px;font-weight:700;">raw_refs</div>
          <pre style="white-space:pre-wrap;word-break:break-word;color:#cfd8dc;font-size:11px;line-height:1.35;margin:0;max-height:160px;overflow:auto;">${prettyJson(evidence?.raw_refs)}</pre>
        </div>
      </div>
    `;
  }

  async function init() {
    user = window.__pmcUser || user;
    if (!user && window.__pmcUserReady) user = await window.__pmcUserReady;
    if (!user) user = (await fetch('/api/auth/me').then(r => r.json()).catch(() => ({}))).user;

    const root = document.getElementById('hermes-opportunity-review-section');
    if (!root) return;
    if (!user || user.id == null) {
      root.innerHTML = '<div style="padding:20px;color:#888;">로그인이 필요합니다.</div>';
      return;
    }
    if (root.dataset.initialized !== '1') {
      root.dataset.initialized = '1';
      renderShell(root);
    }
    await refresh();
  }

  function renderShell(root) {
    root.innerHTML = `
      <div style="margin-bottom:16px;">
        <h1 style="font-size:22px;color:#fff;margin:0 0 4px;">🧠 Hermes Opportunity Review</h1>
        <p style="color:#aaa;font-size:13px;margin:0;line-height:1.5;">
          Hermes-generated Opportunity만 검토합니다. Approved는 Opportunity Inbox 검토 완료 의미이며 marketplace 실행 승인이 아닙니다.
        </p>
      </div>

      <div style="background:#1a1a2e;border:1px solid #2a2a4a;border-radius:12px;padding:14px;margin-bottom:14px;">
        <div style="display:flex;gap:8px;flex-wrap:wrap;align-items:end;">
          <label style="color:#aaa;font-size:11px;">SKU<br>
            <input id="hor-filter-sku" type="text" placeholder="202551129453" style="width:150px;padding:7px;background:#0f0f23;border:1px solid #333;color:#fff;border-radius:4px;font-size:12px;">
          </label>
          <label style="color:#aaa;font-size:11px;">status<br>
            <select id="hor-filter-status" style="padding:7px;background:#0f0f23;border:1px solid #333;color:#fff;border-radius:4px;font-size:12px;">
              <option value="">전체</option>
              ${STATUSES.map(s => `<option value="${s}">${s}</option>`).join('')}
            </select>
          </label>
          <label style="color:#aaa;font-size:11px;">opportunity_type<br>
            <select id="hor-filter-type" style="padding:7px;background:#0f0f23;border:1px solid #333;color:#fff;border-radius:4px;font-size:12px;max-width:230px;">
              <option value="">전체</option>
              ${TYPES.map(t => `<option value="${t}">${t}</option>`).join('')}
            </select>
          </label>
          <button id="hor-apply" type="button" style="padding:8px 14px;background:#1565c0;border:none;border-radius:5px;color:#fff;font-size:12px;font-weight:700;cursor:pointer;">필터 적용</button>
          <button id="hor-reset" type="button" style="padding:8px 14px;background:#37474f;border:none;border-radius:5px;color:#fff;font-size:12px;cursor:pointer;">초기화</button>
          <button id="hor-refresh" type="button" style="margin-left:auto;padding:8px 14px;background:#263238;border:none;border-radius:5px;color:#fff;font-size:12px;cursor:pointer;">새로고침</button>
        </div>
      </div>

      <div style="display:grid;grid-template-columns:minmax(360px,1fr) minmax(420px,1.15fr);gap:14px;align-items:start;">
        <div style="background:#1a1a2e;border:1px solid #2a2a4a;border-radius:12px;padding:14px;">
          <div id="hor-count" style="color:#aaa;font-size:11px;margin-bottom:10px;">로딩 중...</div>
          <div id="hor-list"></div>
        </div>
        <div id="hor-detail" style="background:#1a1a2e;border:1px solid #2a2a4a;border-radius:12px;padding:14px;color:#888;">
          <div style="text-align:center;padding:40px 0;">왼쪽에서 Hermes opportunity를 선택하세요.</div>
        </div>
      </div>
    `;

    document.getElementById('hor-apply').addEventListener('click', refresh);
    document.getElementById('hor-refresh').addEventListener('click', refresh);
    document.getElementById('hor-reset').addEventListener('click', () => {
      document.getElementById('hor-filter-sku').value = '';
      document.getElementById('hor-filter-status').value = '';
      document.getElementById('hor-filter-type').value = '';
      refresh();
    });
    document.getElementById('hor-filter-sku').addEventListener('keydown', e => { if (e.key === 'Enter') refresh(); });
  }

  async function refresh() {
    const params = new URLSearchParams({ limit: '100' });
    const sku = document.getElementById('hor-filter-sku')?.value.trim();
    const status = document.getElementById('hor-filter-status')?.value;
    const type = document.getElementById('hor-filter-type')?.value;
    if (sku) params.set('sku', sku);
    if (status) params.set('status', status);
    if (type) params.set('opportunity_type', type);

    const list = document.getElementById('hor-list');
    try {
      const res = await fetch('/api/opportunity-inbox/hermes?' + params.toString(), { credentials: 'include' });
      const json = await res.json().catch(() => ({}));
      if (!res.ok) throw new Error(json.error || `load failed (${res.status})`);
      cache = Array.isArray(json.data) ? json.data : [];
      renderList();
      if (selectedId && cache.some(r => r.id === selectedId)) renderDetail(cache.find(r => r.id === selectedId));
    } catch (e) {
      if (list) list.innerHTML = `<div style="padding:20px;color:#ef9a9a;">로드 실패: ${esc(e.message)}</div>`;
    }
  }

  function renderList() {
    const list = document.getElementById('hor-list');
    const count = document.getElementById('hor-count');
    if (!list) return;
    if (count) count.textContent = `Hermes-generated ${cache.length}건`;
    if (cache.length === 0) {
      list.innerHTML = '<div style="padding:24px;color:#888;text-align:center;">Hermes-generated opportunity가 없습니다.</div>';
      return;
    }
    list.innerHTML = cache.map(r => {
      const active = r.id === selectedId;
      return `
        <div class="hor-row" data-id="${r.id}" style="padding:10px 12px;border:1px solid ${active ? '#81d4fa' : '#2a2a4a'};border-radius:8px;margin-bottom:8px;background:${active ? '#0a1a2e' : '#0f0f23'};cursor:pointer;">
          <div style="display:flex;gap:6px;align-items:center;flex-wrap:wrap;margin-bottom:6px;">
            ${badge(r.status)}
            <span style="background:#263238;color:#ce93d8;padding:2px 6px;border-radius:4px;font-size:10px;font-family:monospace;">${esc(r.type)}</span>
            <span style="margin-left:auto;color:#666;font-size:11px;">#${r.id}</span>
          </div>
          <div style="color:#fff;font-size:13px;line-height:1.35;margin-bottom:5px;">${esc(r.title || '(no title)')}</div>
          <div style="color:#aaa;font-size:11px;">SKU ${esc(r.sku || '-')} · priority ${esc(r.priority || '-')} · ${fmtDate(r.created_at)}</div>
        </div>
      `;
    }).join('');
    list.querySelectorAll('.hor-row').forEach(row => {
      row.addEventListener('click', () => select(parseInt(row.dataset.id, 10)));
    });
  }

  function select(id) {
    selectedId = id;
    renderList();
    const row = cache.find(r => r.id === id);
    if (row) renderDetail(row);
  }

  function renderDetail(r) {
    const detail = document.getElementById('hor-detail');
    if (!detail) return;
    const review = r.hermes_review || null;
    const hasListingEvidence = r.type === 'listing_quality_review';
    const cachedEvidence = evidenceCache.get(r.id);
    detail.innerHTML = `
      <div style="display:flex;justify-content:space-between;gap:8px;align-items:flex-start;flex-wrap:wrap;margin-bottom:12px;">
        <div>
          <div style="display:flex;gap:6px;align-items:center;flex-wrap:wrap;margin-bottom:6px;">${badge(r.status)}<span style="color:#666;font-size:11px;">#${r.id}</span></div>
          <h2 style="color:#fff;font-size:16px;margin:0;line-height:1.35;">${esc(r.title || '(no title)')}</h2>
          <div style="color:#aaa;font-size:12px;margin-top:6px;">SKU <strong style="color:#fff;">${esc(r.sku || '-')}</strong> · type <code style="color:#ce93d8;">${esc(r.type || '-')}</code></div>
        </div>
        <div style="color:#666;font-size:11px;text-align:right;">created<br>${fmtDate(r.created_at)}</div>
      </div>

      <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:10px;">
        <div style="background:#0f0f23;border-radius:6px;padding:10px;"><div style="color:#aaa;font-size:11px;margin-bottom:5px;">priority</div><div style="color:#fff;font-weight:700;">${esc(r.priority || '-')}</div></div>
        <div style="background:#0f0f23;border-radius:6px;padding:10px;"><div style="color:#aaa;font-size:11px;margin-bottom:5px;">status</div><div>${badge(r.status)}</div></div>
      </div>

      <div style="background:#0f0f23;border-radius:6px;padding:10px;margin-bottom:10px;">
        <div style="color:#aaa;font-size:11px;margin-bottom:6px;font-weight:700;">source_signals</div>${chips(r.source_signals)}
      </div>
      <div style="background:#0f0f23;border-radius:6px;padding:10px;margin-bottom:10px;">
        <div style="color:#aaa;font-size:11px;margin-bottom:6px;font-weight:700;">source_recommendations</div>${chips(r.source_recommendations)}
      </div>
      <div style="background:#0f0f23;border-radius:6px;padding:10px;margin-bottom:10px;">
        <div style="color:#aaa;font-size:11px;margin-bottom:6px;font-weight:700;">market_analysis</div>
        <pre style="white-space:pre-wrap;word-break:break-word;color:#cfd8dc;font-size:11px;line-height:1.4;margin:0;max-height:220px;overflow:auto;">${prettyJson(r.market_analysis)}</pre>
      </div>
      ${review ? `<div style="background:#13251a;border:1px solid #1b5e20;border-radius:6px;padding:10px;margin-bottom:10px;"><div style="color:#69f0ae;font-size:11px;font-weight:700;margin-bottom:5px;">last Hermes review</div><pre style="white-space:pre-wrap;color:#c8e6c9;font-size:11px;margin:0;">${prettyJson(review)}</pre></div>` : ''}
      ${hasListingEvidence ? `
        <div style="background:#0f0f23;border:1px solid #24505f;border-radius:6px;padding:10px;margin-bottom:10px;">
          <div style="display:flex;justify-content:space-between;gap:8px;align-items:center;flex-wrap:wrap;">
            <div>
              <div style="color:#80deea;font-size:11px;font-weight:700;margin-bottom:4px;">Listing Evidence</div>
              <div style="color:#90a4ae;font-size:11px;">Read-only evidence for listing_quality_review. Does not create action plans or modify listing data.</div>
            </div>
            <button id="hor-load-listing-evidence" type="button" style="padding:7px 12px;background:#006064;border:none;border-radius:5px;color:#fff;font-size:12px;font-weight:700;cursor:pointer;">${cachedEvidence ? 'Reload evidence' : 'Load evidence'}</button>
          </div>
          <div id="hor-listing-evidence-output">${cachedEvidence ? renderListingEvidence(cachedEvidence) : ''}</div>
        </div>
      ` : ''}

      <div style="background:#261f12;border:1px solid #5d3a00;border-radius:6px;padding:10px;color:#ffcc80;font-size:12px;line-height:1.5;margin-bottom:12px;">
        Safety: Approved = Opportunity Inbox human review only. This UI never executes marketplace writes or price/inventory/listing changes.
      </div>

      <div style="display:flex;gap:6px;flex-wrap:wrap;">
        ${ACTIONS.map(a => `<button data-hor-action="${a}" type="button" style="padding:7px 12px;background:${a === 'rejected' ? '#4a1a1a' : a === 'approved' ? '#1b5e20' : '#37474f'};border:none;border-radius:5px;color:#fff;font-size:12px;font-weight:700;cursor:pointer;">${esc(a)}</button>`).join('')}
      </div>
      <div id="hor-action-msg" style="min-height:18px;margin-top:10px;font-size:12px;"></div>
    `;
    detail.querySelectorAll('[data-hor-action]').forEach(btn => {
      btn.addEventListener('click', () => reviewAction(r.id, btn.dataset.horAction));
    });
    const evidenceBtn = document.getElementById('hor-load-listing-evidence');
    if (evidenceBtn) evidenceBtn.addEventListener('click', () => loadListingEvidence(r.id));
  }

  async function loadListingEvidence(id) {
    const output = document.getElementById('hor-listing-evidence-output');
    if (output) output.innerHTML = '<div style="color:#aaa;font-size:12px;margin-top:10px;">Loading read-only listing evidence...</div>';
    try {
      const res = await fetch(`/api/opportunity-inbox/hermes/${id}/listing-evidence`, { credentials: 'include' });
      const json = await res.json().catch(() => ({}));
      if (!res.ok) throw new Error(json.error || `listing evidence failed (${res.status})`);
      const evidence = json.data || json;
      evidenceCache.set(id, evidence);
      if (output) output.innerHTML = renderListingEvidence(evidence);
    } catch (e) {
      if (output) output.innerHTML = `<div style="color:#ef9a9a;font-size:12px;margin-top:10px;">Listing evidence load failed: ${esc(e.message)}</div>`;
    }
  }

  async function reviewAction(id, action) {
    let reason = null;
    if (action === 'rejected') {
      reason = prompt('Rejected reason is required:');
      if (reason == null) return;
      reason = String(reason).trim();
      if (!reason) {
        alert('Rejected action requires reason.');
        return;
      }
    } else if (!confirm(`Set Hermes opportunity #${id} to ${action}?\n\nThis only updates Opportunity Inbox review status and metadata.`)) {
      return;
    }

    const msg = document.getElementById('hor-action-msg');
    if (msg) msg.innerHTML = '<span style="color:#aaa;">저장 중...</span>';
    try {
      const res = await fetch(`/api/opportunity-inbox/hermes/${id}/review`, {
        method: 'POST',
        credentials: 'include',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action, reason }),
      });
      const json = await res.json().catch(() => ({}));
      if (!res.ok) throw new Error(json.error || `review failed (${res.status})`);
      if (msg) msg.innerHTML = '<span style="color:#69f0ae;">✓ review saved</span>';
      await refresh();
      selectedId = id;
      const row = cache.find(r => r.id === id);
      if (row) renderDetail(row);
    } catch (e) {
      if (msg) msg.innerHTML = `<span style="color:#ef9a9a;">실패: ${esc(e.message)}</span>`;
      else alert('실패: ' + e.message);
    }
  }

  window.pmcHermesOpportunityReview = { init, refresh };
})();
